import React from 'react';
import TablePanel from './TablePanel';
import FormPanel from './FormPanel';
import { Scissors } from 'lucide-react';

const AdminDashboard = ({ 
  appointments, 
  onEdit, 
  onDeleteRequest, 
  onGoHome, 
  editingId, 
  form, 
  setForm, 
  onSubmit, 
  onCancel 
}) => {
  return (
    <div style={{ background: '#f9f9f9', minHeight: '100vh', padding: '20px' }}>
      {/* HEADER DO PAINEL */}
      <header style={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center', 
        background: '#000', 
        padding: '20px 40px',
        marginBottom: '30px',
        borderBottom: '3px solid var(--amarelo)'
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
          <Scissors color="var(--amarelo)" size={28} />
          <h1 style={{ color: 'white', fontFamily: 'Cormorant Garamond', fontSize: '28px', margin: 0 }}>
            Painel do Barbeiro
          </h1>
        </div>
        <button 
          onClick={onGoHome}
          style={{ 
            background: 'transparent', 
            color: 'var(--amarelo)', 
            border: '1px solid var(--amarelo)',
            padding: '8px 20px',
            cursor: 'pointer',
            fontWeight: 'bold'
          }}
        >
          Sair do Painel
        </button>
      </header>

      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: editingId ? '1fr 400px' : '1fr', 
        gap: '20px',
        maxWidth: '1400px',
        margin: '0 auto'
      }}>
        
        {/* LISTA DE CLIENTES (Sua TablePanel) */}
        <div style={{ background: 'white', padding: '20px', borderRadius: '8px', boxShadow: '0 4px 10px rgba(0,0,0,0.05)' }}>
          <TablePanel 
            appointments={appointments} 
            onEdit={onEdit} 
            onDeleteRequest={onDeleteRequest} 
          />
        </div>

        {/* FORMULÁRIO DE EDIÇÃO (Só aparece se estiver editando) */}
        {editingId && (
          <div className="animate-reveal">
            <FormPanel 
              form={form} 
              setForm={setForm} 
              editing={true} 
              onSubmit={onSubmit} 
              onCancel={onCancel} 
            />
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;
